+    assert!(SentinelKind::Freshness.is_upper_bound());
+    assert!(SentinelKind::Drift.is_upper_bound());
+    assert!(!SentinelKind::Coverage.is_upper_bound());
+    assert!(!SentinelKind::Completeness.is_upper_bound());
+}
